agent_output:
{
  "executive_summary": "Integration architecture for a logistics platform connecting three external systems (SAP ERP via SFTP/XML, DHL Carrier API via REST/webhooks, Analytics via Kafka) using an event-driven backbone with dedicated Anti-Corruption Layers per integration. The design centers on a single internal event bus that decouples all three integrations from each other and from the core domain, with adapter components translating between each external system's protocol/format and the platform's canonical event model.",

  "architecture": {
    "components": [
      {
        "name": "Core Domain Service",
        "responsibility": "Owns the order and delivery lifecycle. Publishes canonical domain events (OrderPlaced, OrderConfirmed, etc.) to the internal event bus. This is the single source of truth for order/shipment state.",
        "boundaries": "No direct knowledge of SAP, DHL, or Kafka. Communicates exclusively through domain events and command interfaces."
      },
      {
        "name": "Internal Event Bus",
        "responsibility": "Brokers all domain events between the core domain and integration adapters. Provides at-least-once delivery guarantees with ordered partitioning by order ID. Kafka is the recommended implementation to reuse infrastructure with System C.",
        "boundaries": "Carries only canonical domain events in the platform's ubiquitous language. External system formats never appear on this bus."
      },
      {
        "name": "SAP ERP Adapter (System A ACL)",
        "responsibility": "Subscribes to OrderConfirmed events from the internal bus. Transforms canonical events into SAP-specific XML format. Batches and delivers files via SFTP on a 15-minute schedule. Handles SFTP connection failures, retries, and delivery confirmation tracking.",
        "boundaries": "Outbound-only adapter. Owns the XML schema mapping and SFTP connection lifecycle. Never leaks SAP XML structure back into the domain."
      },
      {
        "name": "DHL Carrier Adapter (System B ACL)",
        "responsibility": "Two sub-components: (1) Outbound Client — calls DHL REST API to create shipments when ShipmentCreated events occur. (2) Inbound Webhook Receiver — accepts DHL webhook callbacks, translates them into canonical domain events (DeliveryAttempted, DeliveryCompleted, DeliveryFailed), and publishes to the internal bus. Must respond to webhooks within 500ms.",
        "boundaries": "Owns the DHL API contract, authentication, rate limiting, and retry logic. Translates between DHL's data model and the platform's canonical model. The webhook receiver is a separate deployable to allow independent scaling."
      },
      {
        "name": "DHL Webhook Receiver (Fast Path)",
        "responsibility": "Lightweight HTTP endpoint dedicated to receiving DHL webhook callbacks. Validates signature, persists raw payload to a durable queue, returns 200 within 500ms. A downstream consumer processes the queue, translates events, and publishes to the internal bus.",
        "boundaries": "Stateless except for idempotency tracking. Decoupled from event translation to guarantee the 500ms SLA."
      },
      {
        "name": "Analytics Stream Adapter (System C ACL)",
        "responsibility": "Subscribes to ALL domain events on the internal bus and forwards them to the external Analytics Kafka cluster. Handles schema translation to the analytics team's expected format, topic routing, and backpressure.",
        "boundaries": "Read-only consumer of domain events. Owns the mapping from canonical events to the analytics schema. If the analytics cluster is down, buffers events without affecting the core domain."
      },
      {
        "name": "Outbox/Relay",
        "responsibility": "Implements the Transactional Outbox pattern. Domain state changes and their corresponding events are written atomically to the database. A relay process tails the outbox table and publishes to the internal event bus, guaranteeing no events are lost even if the broker is temporarily unavailable.",
        "boundaries": "Sits between the Core Domain Service and the Internal Event Bus. Ensures exactly-once semantics from domain write to event publication."
      },
      {
        "name": "Dead Letter Queue + Alerting",
        "responsibility": "Captures events that fail processing after retry exhaustion in any adapter. Provides visibility, manual replay capability, and alerting for operational teams.",
        "boundaries": "Cross-cutting concern. Each adapter routes its own failures here."
      }
    ],
    "interfaces": [
      {
        "from": "Core Domain Service",
        "to": "Outbox/Relay",
        "contract": "Transactional write: domain state change + event record written atomically in the same DB transaction. Event schema: {event_id, event_type, aggregate_id, aggregate_type, payload, occurred_at, published_at}",
        "coupling_type": "tight (shared database, intentional — this is the consistency boundary)"
      },
      {
        "from": "Outbox/Relay",
        "to": "Internal Event Bus (Kafka)",
        "contract": "Publishes canonical domain events to topic 'logistics.domain.events', partitioned by order_id for ordering guarantees. Avro or JSON Schema with schema registry for forward/backward compatibility.",
        "coupling_type": "loose (async, schema-governed)"
      },
      {
        "from": "Internal Event Bus",
        "to": "SAP ERP Adapter",
        "contract": "Consumes OrderConfirmed events via consumer group 'sap-erp-adapter'. Adapter owns its own consumer offset.",
        "coupling_type": "loose (async, consumer-group isolation)"
      },
      {
        "from": "SAP ERP Adapter",
        "to": "SAP ERP (System A)",
        "contract": "XML files conforming to SAP IDoc/BAPI schema, delivered via SFTP to configured directory. Filename convention: ORDER_CONFIRMED_{batch_id}_{timestamp}.xml. Delivery every 15 minutes.",
        "coupling_type": "loose (file-based, temporal decoupling via batching)"
      },
      {
        "from": "Internal Event Bus",
        "to": "DHL Carrier Adapter (Outbound)",
        "contract": "Consumes ShipmentCreated events via consumer group 'dhl-carrier-adapter'. Calls DHL REST API to create shipment, registers webhook callback URL.",
        "coupling_type": "loose (async consumption) → tight (synchronous REST call to DHL, behind circuit breaker)"
      },
      {
        "from": "DHL API (System B)",
        "to": "DHL Webhook Receiver",
        "contract": "HTTP POST with DHL-specific JSON payload + HMAC signature header. Receiver returns 200/202 within 500ms. Payload includes shipment_id, status, timestamp, failure_reason (optional).",
        "coupling_type": "tight (synchronous HTTP, but minimized via fast-ack pattern)"
      },
      {
        "from": "DHL Webhook Receiver",
        "to": "Internal Event Bus",
        "contract": "Raw webhook payloads persisted to an ingest queue/topic. A consumer translates and publishes canonical DeliveryAttempted/DeliveryCompleted/DeliveryFailed events.",
        "coupling_type": "loose (async, two-stage processing)"
      },
      {
        "from": "Internal Event Bus",
        "to": "Analytics Stream Adapter",
        "contract": "Consumes ALL event types via consumer group 'analytics-stream-adapter'. Transforms to analytics schema and produces to external Kafka cluster topics.",
        "coupling_type": "loose (async, independent consumer group, separate Kafka cluster)"
      }
    ],
    "data_flow": "1. Core Domain writes state + event atomically (Outbox). 2. Relay publishes to internal Kafka topic 'logistics.domain.events'. 3. Three independent consumer groups each process events at their own pace: SAP adapter batches OrderConfirmed into XML/SFTP every 15min; DHL adapter reacts to ShipmentCreated by calling DHL API; Analytics adapter forwards all events to external Kafka. 4. Inbound: DHL webhooks hit the fast-path receiver, get ack'd in <500ms, raw payload queued, then translated into canonical events and published back to the internal bus — completing the feedback loop for delivery status tracking.",
    "patterns_used": [
      {
        "pattern": "Transactional Outbox",
        "rationale": "Guarantees atomic consistency between domain state changes and event publication. Eliminates dual-write problem where the DB commits but the broker publish fails (or vice versa). Critical for a system where lost events mean lost shipments or incorrect analytics."
      },
      {
        "pattern": "Anti-Corruption Layer (per integration)",
        "rationale": "Each external system has its own data model, protocol, and reliability characteristics. ACLs prevent SAP's XML schema, DHL's REST contract, and the analytics Kafka schema from polluting the core domain model. When DHL changes their API, only one adapter changes."
      },
      {
        "pattern": "Fast Ack + Async Processing (for webhooks)",
        "rationale": "DHL mandates 500ms response time. By immediately persisting the raw payload and returning 200, we decouple receipt from processing. Translation, validation, and domain event publication happen asynchronously without risking the SLA."
      },
      {
        "pattern": "Consumer Group Isolation",
        "rationale": "Each integration adapter runs as an independent Kafka consumer group. SAP adapter lag doesn't block DHL processing. Analytics backpressure doesn't affect operational integrations. Each can be scaled, restarted, or redeployed independently."
      },
      {
        "pattern": "Circuit Breaker (DHL outbound calls)",
        "rationale": "DHL REST API is a synchronous dependency. Circuit breaker prevents cascade failure when DHL is down — events queue up and are retried when the circuit closes."
      },
      {
        "pattern": "Batch Accumulator (SAP adapter)",
        "rationale": "SAP expects files every 15 minutes, not individual events. The adapter accumulates OrderConfirmed events and flushes as a single XML batch file, matching the integration contract naturally."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": ["Order (root: order_id) — states: Placed → Confirmed → Shipped → Delivered/Failed. Owns OrderPlaced, OrderConfirmed events."]
      },
      {
        "name": "Shipment Management",
        "classification": "core",
        "aggregates": ["Shipment (root: shipment_id, refs order_id) — states: Created → InTransit → Delivered/Failed. Owns ShipmentCreated, DeliveryAttempted, DeliveryCompleted, DeliveryFailed events."]
      },
      {
        "name": "ERP Integration",
        "classification": "generic",
        "aggregates": ["ExportBatch (root: batch_id) — tracks which OrderConfirmed events have been exported, batch status, delivery confirmation via SFTP."]
      },
      {
        "name": "Carrier Integration",
        "classification": "supporting",
        "aggregates": ["CarrierShipment (root: carrier_tracking_id, refs shipment_id) — maps between internal shipment IDs and DHL tracking IDs. Tracks webhook delivery status."]
      },
      {
        "name": "Event Streaming (Analytics)",
        "classification": "generic",
        "aggregates": ["StreamPosition — tracks consumer offsets and last-published positions for exactly-once delivery to external analytics cluster."]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Shipment Management",
        "relationship": "Customer-Supplier — Order Management publishes OrderConfirmed, Shipment Management reacts by creating shipments. Order Management defines the event schema."
      },
      {
        "upstream": "Order Management",
        "downstream": "ERP Integration",
        "relationship": "Conformist with ACL — ERP Integration conforms to the domain event schema but translates to SAP's XML format via its Anti-Corruption Layer."
      },
      {
        "upstream": "Shipment Management",
        "downstream": "Carrier Integration",
        "relationship": "Customer-Supplier with ACL — Shipment Management publishes ShipmentCreated. Carrier Integration translates to DHL's API model. Inbound DHL webhooks are translated back via the ACL."
      },
      {
        "upstream": "Order Management + Shipment Management",
        "downstream": "Event Streaming (Analytics)",
        "relationship": "Open Host Service / Published Language — All domain events are published in a canonical schema. Analytics consumes as a downstream conformist."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Single internal Kafka cluster as the event backbone",
      "gains": "Unified event infrastructure, natural fit for Analytics (System C) requirement, proven at-least-once delivery, consumer group isolation gives each adapter independence, operational team manages one broker technology",
      "sacrifices": "Kafka operational complexity (ZooKeeper/KRaft, partition management), overkill if event volume is low, latency floor of ~10-50ms for internal events",
      "alternatives_considered": ["RabbitMQ (simpler ops but weaker ordering guarantees and no native Kafka compatibility for System C)", "Database polling (simpler but higher latency and polling overhead)", "Direct point-to-point integration (eliminates broker but creates tight coupling between all systems)"]
    },
    {
      "decision": "Fast-ack webhook pattern (persist raw, process async) for DHL",
      "gains": "Guarantees 500ms SLA regardless of downstream processing time, survives temporary internal bus outages, raw payload preserved for debugging and replay",
      "sacrifices": "Added complexity of two-stage processing, potential for processing lag between ack and domain event publication, need idempotency handling for webhook retries",
      "alternatives_considered": ["Synchronous inline processing (simpler but risks breaching 500ms SLA under load or when Kafka is slow)", "Lambda/serverless webhook receiver (auto-scales but adds cold-start latency risk)"]
    },
    {
      "decision": "Transactional Outbox over direct Kafka publish from domain service",
      "gains": "Zero event loss — if the business state changed, the event is guaranteed to be published. No dual-write problem.",
      "sacrifices": "Added DB load from outbox table writes, relay process adds latency (typically <100ms), outbox table needs periodic cleanup",
      "alternatives_considered": ["CDC (Change Data Capture) via Debezium — powerful but adds infrastructure complexity and couples event schema to DB schema", "Direct publish with manual compensation — simpler but risks silent event loss"]
    },
    {
      "decision": "Separate deployable for DHL Webhook Receiver vs. monolithic adapter",
      "gains": "Webhook receiver can be scaled independently to handle burst webhook traffic, failure in event translation doesn't affect webhook receipt, clear SLA boundary",
      "sacrifices": "Additional deployment unit to manage, network hop between receiver and translator",
      "alternatives_considered": ["Single adapter process with internal async queue (simpler deployment but SLA risk if process is overloaded)"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Adding new external system integrations",
      "evolution_path": "New adapters subscribe to the internal event bus as independent consumer groups. Zero changes to core domain or existing adapters. E.g., adding a FedEx carrier or a new ERP system is purely additive."
    },
    {
      "area": "Changing carrier from DHL to another provider",
      "evolution_path": "Replace the DHL Carrier Adapter ACL with a new carrier-specific adapter. Internal domain events (ShipmentCreated, DeliveryCompleted, etc.) remain unchanged. The ACL absorbs the entire translation difference."
    },
    {
      "area": "SAP batch frequency changes",
      "evolution_path": "The batch accumulator interval is a configuration parameter. Moving from 15-minute to 5-minute or real-time batches requires only config change, not architectural change."
    },
    {
      "area": "Event schema evolution",
      "evolution_path": "Schema registry with compatibility checks (backward/forward) allows adding fields to domain events without breaking existing consumers. Each adapter pins to a schema version it understands."
    },
    {
      "area": "Analytics platform migration",
      "evolution_path": "Analytics Stream Adapter is the only component aware of the external Kafka cluster. Switching to a different analytics platform (e.g., direct HTTP, Snowflake streaming) means replacing one adapter."
    }
  ],

  "rigidity_points": [
    {
      "area": "Canonical domain event schema",
      "reason": "All three integrations depend on the same internal event contract. Renaming events or changing their structure requires coordinated updates across all adapters. This is intentional — the canonical model IS the integration contract and should change slowly and deliberately."
    },
    {
      "area": "Kafka as internal event bus",
      "reason": "Deep dependency. Consumer group semantics, partitioning strategy, and ordering guarantees are baked into every adapter. Swapping Kafka for another broker is a major effort. This is acceptable because Kafka is proven infrastructure and the Analytics requirement already mandates Kafka compatibility."
    },
    {
      "area": "Transactional Outbox tied to the core domain's database",
      "reason": "The outbox table must live in the same database as the domain aggregates to participate in the same transaction. Database migration or sharding must account for the outbox."
    }
  ],

  "risks": [
    {
      "risk": "DHL webhook replay/duplicate delivery causing duplicate domain events (DeliveryCompleted published twice)",
      "severity": "high",
      "mitigation": "Idempotency key on webhook payload (DHL event ID + shipment ID). Webhook receiver deduplicates before queueing. Domain service enforces state machine transitions — a Shipment already in Delivered state rejects a second DeliveryCompleted."
    },
    {
      "risk": "SAP SFTP delivery failure causing order confirmation backlog",
      "severity": "high",
      "mitigation": "Retry with exponential backoff. Failed batches are preserved and re-queued. Alerting on consecutive failures. Circuit breaker on SFTP connection to avoid resource exhaustion. Batch ID tracking ensures no duplicate deliveries on retry."
    },
    {
      "risk": "Outbox relay lag under high event volume causing stale data in integrations",
      "severity": "medium",
      "mitigation": "Monitor relay lag metric. Scale relay process horizontally (partition outbox table by aggregate ID). Set alerting threshold on lag > 1 second."
    },
    {
      "risk": "Analytics Kafka cluster backpressure causing internal event bus consumer lag",
      "severity": "medium",
      "mitigation": "Analytics adapter runs as an isolated consumer group — its lag cannot affect SAP or DHL adapters. Internal buffering with backpressure signaling. If external cluster is down, adapter pauses consumption and resumes when available (Kafka retains events)."
    },
    {
      "risk": "Schema drift between canonical events and external system expectations",
      "severity": "medium",
      "mitigation": "Schema registry with compatibility enforcement. Contract tests per adapter. CI pipeline validates schema changes against all adapter deserializers before deployment."
    },
    {
      "risk": "DHL API rate limiting or outage blocking shipment creation",
      "severity": "high",
      "mitigation": "Circuit breaker pattern on DHL outbound client. When open, ShipmentCreated events queue in Kafka and are retried when circuit closes. Rate limiter respects DHL's published limits. Alert on circuit-open duration."
    },
    {
      "risk": "Webhook receiver becomes a single point of failure for delivery tracking",
      "severity": "critical",
      "mitigation": "Deploy webhook receiver behind a load balancer with multiple instances. Health checks with automatic instance replacement. If all instances fail, DHL will retry webhooks per their retry policy. Raw payloads in durable queue survive receiver restarts."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Phase 1: Stand up the internal Kafka event bus and Transactional Outbox in the core domain service. This is the foundation everything else depends on. Phase 2: Build the Analytics Stream Adapter (System C) — it's the simplest consumer (read-only, all events) and validates the event bus end-to-end. Phase 3: Build the DHL Carrier Adapter with webhook receiver — the most complex integration due to bidirectional communication and SLA requirements. Phase 4: Build the SAP ERP Adapter — straightforward batch consumer with SFTP delivery. Each phase is independently deployable and testable.",
    "files_to_create_or_modify": [
      "core/domain/events/ — Canonical event definitions (OrderPlaced, OrderConfirmed, ShipmentCreated, DeliveryAttempted, DeliveryCompleted, DeliveryFailed)",
      "core/infrastructure/outbox/ — Outbox table migration, OutboxRelay service, OutboxRepository",
      "adapters/sap-erp/ — SapOrderConfirmedConsumer, XmlBatchBuilder, SftpDeliveryClient, BatchTracker",
      "adapters/dhl-carrier/outbound/ — DhlShipmentClient, CircuitBreakerConfig, ShipmentCreatedConsumer",
      "adapters/dhl-carrier/inbound/ — WebhookReceiverController, WebhookPayloadStore, WebhookEventTranslator, IdempotencyFilter",
      "adapters/analytics-stream/ — AnalyticsEventConsumer, AnalyticsSchemaMapper, ExternalKafkaProducer",
      "infrastructure/kafka/ — Topic configuration, consumer group configs, schema registry setup",
      "infrastructure/monitoring/ — Lag monitors, circuit breaker dashboards, DLQ alerting"
    ],
    "patterns_to_follow": "Each adapter follows the Hexagonal Architecture (Ports & Adapters) pattern: the core domain defines ports (event interfaces), and each integration is an adapter implementing those ports. Adapters are fully independent packages/modules with their own tests, configuration, and deployment pipelines. Use the Strangler Fig pattern if migrating from existing point-to-point integrations.",
    "pitfalls_to_avoid": [
      "DO NOT let SAP XML schema or DHL API DTOs appear in the core domain — always translate at the ACL boundary",
      "DO NOT process DHL webhooks synchronously before returning 200 — the 500ms SLA will be breached under load",
      "DO NOT share consumer groups between adapters — one slow adapter will block all others",
      "DO NOT skip the Outbox pattern and publish directly to Kafka from the domain service — you will lose events during broker outages",
      "DO NOT use a single monolithic adapter for all three systems — independent failure domains are critical for operational resilience",
      "DO NOT poll DHL for status updates as a fallback without rate limiting — you will get throttled; use webhook retries as the primary mechanism with polling as a reconciliation job"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 88,
    "high_confidence_areas": [
      "Event-driven backbone with Kafka — strong fit given the Analytics Kafka requirement and the need to decouple three independent integrations",
      "Anti-Corruption Layer per integration — textbook application, well-proven pattern",
      "Fast-ack webhook pattern — industry-standard approach for meeting strict webhook SLAs",
      "Transactional Outbox — the correct solution for the dual-write problem in this context"
    ],
    "low_confidence_areas": [
      "Exact Kafka topic partitioning strategy — depends on event volume and ordering requirements that would need load testing to finalize",
      "Whether the DHL webhook receiver needs its own datastore or can use the internal Kafka bus directly as the durable queue — depends on latency measurements",
      "SAP IDoc/BAPI specific XML format — would need SAP integration documentation to finalize the schema mapping"
    ],
    "assumptions": [
      "Event volume is moderate (thousands to tens of thousands per hour, not millions) — at extreme scale, the outbox pattern needs partitioning",
      "DHL provides webhook retry capability and HMAC signature verification",
      "The analytics team's Kafka cluster is a separate cluster from the internal one (common in enterprise setups for security and isolation)",
      "The platform uses a relational database that supports transactions (needed for the Outbox pattern)",
      "SAP integration is outbound-only (confirmed orders pushed to SAP, no inbound SAP events)"
    ]
  }
}
